def gen(rng, size):
    n = max(1, size)
    vals = list(range(n))
    rng.shuffle(vals)
    # build a BST level-order array by simulating inserts
    left = {}
    right = {}
    rootv = vals[0]
    for v in vals[1:]:
        cur = rootv
        while True:
            if v < cur:
                if cur in left:
                    cur = left[cur]
                else:
                    left[cur] = v; break
            else:
                if cur in right:
                    cur = right[cur]
                else:
                    right[cur] = v; break
    # BFS to level-order array with nulls
    arr = []
    queue = [rootv]
    while queue:
        nxt = []
        any_real = False
        for node in queue:
            if node is None:
                arr.append(None)
                nxt.append(None); nxt.append(None)
                continue
            arr.append(node)
            l = left.get(node); r = right.get(node)
            nxt.append(l); nxt.append(r)
            if l is not None or r is not None:
                any_real = True
        if not any_real:
            break
        queue = nxt
    while arr and arr[-1] is None:
        arr.pop()
    k = rng.randint(1, n)
    return [arr, k]

